'use client'
import { cn, getLinkComponent, useSignals } from '@cascivo/core'
import { builtin, t } from '@cascivo/i18n'
import type { HTMLAttributes, ReactNode } from 'react'
import styles from './header.module.css'

export interface HeaderLink {
  /** Stable React key. Provide when `href`/`label` may repeat (e.g. placeholder `#` links). */
  id?: string
  label: string
  href: string
  active?: boolean
}

export interface HeaderLabels {
  nav?: string
}

export interface HeaderProps extends HTMLAttributes<HTMLElement> {
  brand?: ReactNode
  links?: HeaderLink[]
  actions?: ReactNode
  sticky?: boolean
  labels?: HeaderLabels
}

export function Header({
  brand,
  links,
  actions,
  sticky = false,
  labels,
  className,
  ...props
}: HeaderProps) {
  useSignals()
  const LinkComponent = getLinkComponent()
  const navLabel = labels?.nav ?? t(builtin.header.nav)
  return (
    <header
      role="banner"
      data-sticky={sticky || undefined}
      className={cn(styles['header'], className)}
      {...props}
    >
      {brand && <div className={styles['brand']}>{brand}</div>}
      {links && links.length > 0 && (
        <nav aria-label={navLabel} className={styles['nav']}>
          <ul className={styles['list']}>
            {links.map((link, i) => (
              <li key={link.id ?? `${i}-${link.href}`}>
                <LinkComponent
                  href={link.href}
                  aria-current={link.active ? 'page' : undefined}
                  data-state={link.active ? 'active' : undefined}
                  className={styles['link']}
                >
                  {link.label}
                </LinkComponent>
              </li>
            ))}
          </ul>
        </nav>
      )}
      <div className={styles['spacer']} />
      {actions && <div className={styles['actions']}>{actions}</div>}
    </header>
  )
}

@layer cascivo.component {
  .header {
    container: cascade-header / inline-size;
    display: flex;
    align-items: center;
    gap: var(--cascivo-space-6);
    padding-inline: var(--cascivo-space-6);
    padding-block: var(--cascivo-space-3);
    font-family: var(--cascivo-font-sans);
    background-color: var(--cascivo-header-bg, var(--cascivo-color-surface));
    border-block-end: 1px solid var(--cascivo-color-border);

    &[data-sticky] {
      position: sticky;
      inset-block-start: 0;
      z-index: var(--cascivo-z-raised);
    }
  }

  .brand {
    display: flex;
    align-items: center;
    gap: var(--cascivo-space-2);
    font-size: var(--cascivo-text-base);
    font-weight: var(--cascivo-font-semibold);
    color: var(--cascivo-color-text);
    white-space: nowrap;

    & :any-link {
      color: inherit;
      text-decoration: none;
    }
  }

  .nav {
    min-inline-size: 0;
  }

  .list {
    display: flex;
    align-items: center;
    gap: var(--cascivo-space-1);
    margin: 0;
    padding: 0;
    list-style: none;
  }

  .link {
    display: inline-flex;
    align-items: center;
    padding-inline: var(--cascivo-space-3);
    padding-block: var(--cascivo-space-2);
    font-size: var(--cascivo-text-sm);
    line-height: var(--cascivo-leading-none);
    color: var(--cascivo-color-text-subtle);
    text-decoration: none;
    white-space: nowrap;
    border-radius: var(--cascivo-radius-item);
    transition:
      color var(--cascivo-duration-150) var(--cascivo-ease-out),
      background-color var(--cascivo-duration-150) var(--cascivo-ease-out);

    &:hover {
      color: var(--cascivo-color-text);
      background-color: var(--cascivo-color-bg-subtle);
    }

    &:focus-visible {
      outline: none;
      box-shadow: var(--cascivo-focus-ring);
    }

    &[data-state='active'] {
      color: var(--cascivo-color-text);
      font-weight: var(--cascivo-font-medium);
      background-color: var(--cascivo-color-bg-subtle);
    }
  }

  .spacer {
    flex: 1;
  }

  .actions {
    display: flex;
    align-items: center;
    gap: var(--cascivo-space-2);
  }

  /* Narrow container: tighter, smaller nav link labels */
  @container cascade-header (inline-size < 40rem) {
    .list {
      gap: 0;
    }

    .link {
      padding-inline: var(--cascivo-space-2);
      font-size: var(--cascivo-text-xs);
      letter-spacing: var(--cascivo-tracking-tight);
    }
  }
}
